import{_ as l,c as o,o as t,a1 as s}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Claude Code Compatibility","description":"Learn how OpenCode Agent Skills is compatible with Claude Code skills and plugin system. Master tool mapping mechanism, skill discovery priority, and reuse Claude skill ecosystem.","frontmatter":{"title":"Claude Code Compatibility","subtitle":"Claude Code Compatibility","sidebarTitle":"Claude Code","description":"Learn how OpenCode Agent Skills is compatible with Claude Code skills and plugin system. Master tool mapping mechanism, skill discovery priority, and reuse Claude skill ecosystem.","tags":["Compatibility","Claude Code","Skill Reuse"],"prerequisite":["start-what-is-opencode-agent-skills","platforms-skill-discovery-mechanism"],"order":1},"headers":[],"relativePath":"joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md","filePath":"joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"}'),i={name:"joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"};function a(n,e,r,d,c,p){return t(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="claude-code-skill-compatibility" tabindex="-1">Claude Code Skill Compatibility <a class="header-anchor" href="#claude-code-skill-compatibility" aria-label="Permalink to &quot;Claude Code Skill Compatibility&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Understand how plugins automatically support Claude Code skill format</li><li>Master the tool mapping mechanism so Claude skills work correctly in OpenCode</li><li>Learn the complete skill discovery priority rules</li><li>Reuse existing skills from Claude plugin marketplace without rewriting</li></ul><h2 id="your-current-challenge" tabindex="-1">Your Current Challenge <a class="header-anchor" href="#your-current-challenge" aria-label="Permalink to &quot;Your Current Challenge&quot;">​</a></h2><p>You already have some Claude Code skills, or want to use skills from the Claude plugin marketplace, but these skills are written for Claude Code. Using them directly in OpenCode will encounter problems:</p><ul><li>Tool calls in Claude skills (like <code>TodoWrite</code>, <code>Task</code>) don&#39;t exist in OpenCode</li><li>Unclear how to make OpenCode find installed Claude plugin skills</li><li>Worried about skill format incompatibility, requiring rewriting everything</li></ul><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>OpenCode Agent Skills plugin enables you to use Claude Code skills without modification through <strong>three-layer compatibility mechanism</strong>:</p><ol><li><strong>Automatic Discovery</strong> - Scan skills from Claude Code standard directories (<code>.claude/skills/</code>, <code>~/.claude/plugins/</code>)</li><li><strong>Tool Mapping</strong> - Automatically inject tool mapping guide when loading skills, converting Claude tool names to OpenCode tool names</li><li><strong>Format Support</strong> - Support both v1 and v2 installation formats for Claude plugins</li></ol><div class="info custom-block"><p class="custom-block-title">Key Concept</p><p><strong>Claude Code Skill Format</strong> - Skill specification defined by Anthropic, using <code>SKILL.md</code> file to describe skills, containing YAML frontmatter (metadata) and Markdown content (instructions).</p></div><h3 id="tool-mapping-principle" tabindex="-1">Tool Mapping Principle <a class="header-anchor" href="#tool-mapping-principle" aria-label="Permalink to &quot;Tool Mapping Principle&quot;">​</a></h3><p>When the plugin detects that a loaded skill is written for Claude Code, it automatically injects a tool mapping guide:</p><table tabindex="0"><thead><tr><th>Claude Code Tool</th><th>OpenCode Tool</th><th>Mapping Rule</th></tr></thead><tbody><tr><td><code>TodoWrite/TodoRead</code></td><td><code>todowrite/todoread</code></td><td>Lowercase</td></tr><tr><td><code>Task</code> (sub-agent)</td><td><code>task</code> (with subagent_type parameter)</td><td>Use parameter</td></tr><tr><td><code>Skill</code></td><td><code>use_skill</code></td><td>Replace tool name</td></tr><tr><td><code>Read/Write/Edit/Bash/Glob/Grep/WebFetch</code></td><td><code>read/write/edit/bash/glob/grep/webfetch</code></td><td>Lowercase</td></tr></tbody></table><p><strong>Mapping Method</strong>: When loading skills, the plugin injects the mapping guide as XML into the session context, and AI will automatically call the correct tools according to the mapping.</p><div class="tip custom-block"><p class="custom-block-title">Why is mapping needed?</p><p>Claude Code and OpenCode use different tool naming styles. Claude uses PascalCase (like <code>TodoWrite</code>), while OpenCode uses lowercase (like <code>todowrite</code>). Tool mapping lets AI know how to convert calls.</p></div><h3 id="skill-discovery-priority" tabindex="-1">Skill Discovery Priority <a class="header-anchor" href="#skill-discovery-priority" aria-label="Permalink to &quot;Skill Discovery Priority&quot;">​</a></h3><p>The plugin discovers skills in the following order. <strong>The first matched skill takes effect</strong> (same-name skills are not duplicated):</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Skill Discovery Flow] --&gt; B[Project-level OpenCode]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; |.opencode/skills/| C[1. project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Project-level Claude Code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; |.claude/skills/| E[2. claude-project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[User-level OpenCode]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; |~/.config/opencode/skills/| G[3. user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[User-level Claude Code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; |~/.claude/skills/| I[4. claude-user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; J[Claude Plugin Cache]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    J --&gt; |~/.claude/plugins/cache/| K[5. claude-plugins]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K --&gt; L[Claude Plugin Marketplace]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L --&gt; |~/.claude/plugins/marketplaces/| M[6. claude-plugins]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style G fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style I fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style K fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style M fill:#fff4e1</span></span></code></pre></div><p><strong>Priority Rules</strong>:</p><ul><li>Project-level skills override user-level skills (convenient for project customization)</li><li>OpenCode skills take priority over Claude skills (avoid confusion)</li><li>Only the first discovered version is kept for same-name skills</li></ul><details class="details custom-block"><summary>Example: Same-name Skill Override</summary><p>Assuming you have a skill named <code>git-helper</code> in two locations:</p><ul><li><code>.claude/skills/git-helper/SKILL.md</code> (Claude version)</li><li><code>.opencode/skills/git-helper/SKILL.md</code> (OpenCode version)</li></ul><p><strong>Result</strong>: OpenCode version takes effect (higher priority)</p></details><h2 id="🎒-preparation-before-starting" tabindex="-1">🎒 Preparation Before Starting <a class="header-anchor" href="#🎒-preparation-before-starting" aria-label="Permalink to &quot;🎒 Preparation Before Starting&quot;">​</a></h2><ul><li>OpenCode Agent Skills plugin installed and configured</li><li>Understand basic skill concepts (recommended to read <a href="./../../start/what-is-opencode-agent-skills/">What is OpenCode Agent Skills?</a>)</li><li>(Optional) Have Claude Code installed plugins or skills</li></ul><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-check-if-claude-skills-are-discovered" tabindex="-1">Step 1: Check if Claude Skills Are Discovered <a class="header-anchor" href="#step-1-check-if-claude-skills-are-discovered" aria-label="Permalink to &quot;Step 1: Check if Claude Skills Are Discovered&quot;">​</a></h3><p><strong>Why</strong> Confirm that the plugin can correctly scan your Claude Code skill directories.</p><p>Call the tool in OpenCode:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>get_available_skills()</span></span></code></pre></div><p><strong>You should see</strong>: The returned skill list includes skills from <code>.claude/skills/</code>, <code>~/.claude/skills/</code>, <code>~/.claude/plugins/</code>, with each skill&#39;s <code>source</code> field showing the source (like <code>claude-project</code>, <code>claude-user</code>, <code>claude-plugins</code>).</p><p><strong>Checkpoint ✅</strong>: Confirm the list includes the expected Claude skills.</p><h3 id="step-2-load-claude-skills" tabindex="-1">Step 2: Load Claude Skills <a class="header-anchor" href="#step-2-load-claude-skills" aria-label="Permalink to &quot;Step 2: Load Claude Skills&quot;">​</a></h3><p><strong>Why</strong> Verify that the tool mapping mechanism works correctly.</p><p>Call the tool to load a Claude skill:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>use_skill(skill=&quot;your-skill-name&quot;)</span></span></code></pre></div><p><strong>You should see</strong>: Success message returned, like <code>Skill &quot;xxx&quot; loaded.</code></p><p><strong>Checkpoint ✅</strong>: AI can now use the skill&#39;s instructions.</p><h3 id="step-3-verify-tool-mapping-works" tabindex="-1">Step 3: Verify Tool Mapping Works <a class="header-anchor" href="#step-3-verify-tool-mapping-works" aria-label="Permalink to &quot;Step 3: Verify Tool Mapping Works&quot;">​</a></h3><p><strong>Why</strong> Confirm that AI correctly calls OpenCode&#39;s tools instead of Claude&#39;s tools.</p><p>Give AI a task that requires the skill&#39;s tools, for example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Please use the todo feature in the skill to help me create a task list.</span></span></code></pre></div><p><strong>You should see</strong>: AI correctly calls OpenCode&#39;s <code>todowrite</code> tool, not Claude&#39;s <code>TodoWrite</code> tool.</p><div class="tip custom-block"><p class="custom-block-title">How to verify mapping works?</p><p>Check AI&#39;s tool call log (if debug mode is enabled), you&#39;ll see it calls <code>todowrite</code> not <code>TodoWrite</code>.</p></div><p><strong>Checkpoint ✅</strong>: Tool call successful, task completed.</p><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="_1-plugin-format-mismatch" tabindex="-1">1. Plugin Format Mismatch <a class="header-anchor" href="#_1-plugin-format-mismatch" aria-label="Permalink to &quot;1. Plugin Format Mismatch&quot;">​</a></h3><p><strong>Problem</strong>: Old Claude plugins use v1 format, new versions use v2 format, causing some skills not to be discovered.</p><p><strong>Reason</strong>: v1 and v2 have different <code>installed_plugins.json</code> structures.</p><p><strong>Solution</strong>: Plugin supports both formats simultaneously, no manual conversion needed. If skills still can&#39;t be discovered, check if <code>~/.claude/plugins/installed_plugins.json</code> exists and format is correct.</p><h3 id="_2-tool-mapping-not-working" tabindex="-1">2. Tool Mapping Not Working <a class="header-anchor" href="#_2-tool-mapping-not-working" aria-label="Permalink to &quot;2. Tool Mapping Not Working&quot;">​</a></h3><p><strong>Problem</strong>: AI still calls Claude tool names, causing errors.</p><p><strong>Reason</strong>: Skill content might bypass the tool mapping guide, or uses hardcoded tool calls.</p><p><strong>Solution</strong>:</p><ul><li>Confirm skill is loaded before use, not directly calling tools</li><li>If skill has code examples, manually change tool names to OpenCode format</li></ul><h3 id="_3-skill-naming-conflict" tabindex="-1">3. Skill Naming Conflict <a class="header-anchor" href="#_3-skill-naming-conflict" aria-label="Permalink to &quot;3. Skill Naming Conflict&quot;">​</a></h3><p><strong>Problem</strong>: Same-name skills in different locations, loading the wrong version.</p><p><strong>Reason</strong>: Override caused by skill discovery priority.</p><p><strong>Solution</strong>:</p><ul><li>Check the skill&#39;s <code>source</code> field to confirm origin</li><li>Use namespace format to explicitly specify source: <code>use_skill(skill=&quot;user:skill-name&quot;)</code> or <code>use_skill(skill=&quot;claude-plugins:skill-name&quot;)</code></li></ul><details class="details custom-block"><summary>Namespace Syntax</summary><p>Plugin supports <code>namespace:skill-name</code> format:</p><ul><li><code>project:skill-name</code> - Project-level OpenCode skill</li><li><code>claude-project:skill-name</code> - Project-level Claude skill</li><li><code>user:skill-name</code> - User-level OpenCode skill</li><li><code>claude-user:skill-name</code> - User-level Claude skill</li><li><code>claude-plugins:skill-name</code> - Claude plugin marketplace skill</li></ul></details><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>OpenCode Agent Skills plugin lets you seamlessly reuse Claude Code skills through three-layer compatibility mechanism:</p><ul><li><strong>Automatic Discovery</strong> - Scan skills from 6 locations, covering project-level, user-level, and plugin-level</li><li><strong>Tool Mapping</strong> - Automatically convert Claude tool names to OpenCode tool names</li><li><strong>Format Support</strong> - Support both v1 and v2 Claude plugin formats</li></ul><p>No need to rewrite skills, install and use directly, the plugin automatically handles compatibility issues.</p><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>Next lesson we&#39;ll learn <strong><a href="./../superpowers-integration/">Superpowers Workflow Integration</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How to enable Superpowers mode</li><li>Automatic detection and loading of Superpowers skills</li><li>How strict workflows improve development efficiency</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Line Number</th></tr></thead><tbody><tr><td>Tool mapping definition</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L19-L25" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>19-25</td></tr><tr><td>v1/v2 format type definitions</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L35-L61" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>35-61</td></tr><tr><td>Plugin installation path extraction</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L68-L77" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>68-77</td></tr><tr><td>Discover plugin skills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L82-L105" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>82-105</td></tr><tr><td>Discover marketplace skills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L115-L180" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>115-180</td></tr><tr><td>Discover cache skills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L193-L253" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>193-253</td></tr><tr><td>Skill discovery priority list</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L254" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-254</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>toolTranslation import</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L15" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>15</td></tr><tr><td>Tool mapping injection</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L238-L249" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>238-249</td></tr></tbody></table><p><strong>Key Constants</strong>:</p><ul><li><code>toolTranslation</code>: Tool mapping guide XML string, injected into session context when loading skills. Defined in <code>src/claude.ts:19-25</code>, imported in <code>src/tools.ts:15</code></li></ul><p><strong>Key Functions</strong>:</p><ul><li><code>getPluginInstallPaths()</code>: Extract plugin installation paths from v1/v2 formats</li><li><code>discoverSkillsFromPluginDir()</code>: Scan skills/ subdirectory in plugin directory</li><li><code>discoverMarketplaceSkills()</code>: Discover skills from <code>~/.claude/plugins/marketplaces/</code> (priority)</li><li><code>discoverPluginCacheSkills()</code>: Discover skills from <code>~/.claude/plugins/cache/</code> (fallback)</li><li><code>findFile()</code>: Recursively find specified file name (utility function)</li></ul><p><strong>Important Flows</strong>:</p><ol><li>When plugin initializes, call <code>discoverAllSkills()</code> → iterate through 6 discovery paths</li><li>When discovering Claude plugin skills, call <code>discoverMarketplaceSkills()</code> or <code>discoverPluginCacheSkills()</code></li><li>When loading skills, <code>use_skill</code> tool inserts <code>toolTranslation</code> into XML content (line 244)</li></ol></details>`,68)])])}const g=l(i,[["render",a]]);export{h as __pageData,g as default};
